/**
 * Routing policy source of truth.
 *
 * This module is the single canonical definition for:
 *  - Model candidate tiers and their reasoning-effort defaults
 *  - Model family groupings (derived — never listed twice)
 *  - Orchestration keywords that trigger reasoning-tier escalation
 *
 * routing-matrix.md (in references/) documents the same policy in prose form
 * for contributors. When you change a tier, a model, or a keyword here, keep
 * the matrix in sync so the written guidance stays accurate.
 */

/**
 * Ordered candidate lists per tier.
 * The extension tries models in this order and picks the first one that
 * accepts a switch, so order matters for fallback behaviour.
 *
 * @type {{ economy: ModelEntry[], builder: ModelEntry[], reasoning: ModelEntry[] }}
 * @typedef {{ id: string, reasoningEffort?: 'low' | 'medium' | 'high' }} ModelEntry
 */
export const MODEL_CANDIDATES = {
  economy: [
    { id: "claude-haiku-4.5" },
    { id: "gpt-4.1" },
    { id: "gpt-5-mini", reasoningEffort: "low" },
    { id: "gpt-5.4-mini", reasoningEffort: "low" },
  ],
  builder: [
    // Prioritize models with reasoning support for better implementation quality
    { id: "claude-sonnet-4.6", reasoningEffort: "medium" },
    { id: "gpt-5.2", reasoningEffort: "medium" },
    { id: "gpt-5.3-codex", reasoningEffort: "medium" },
    { id: "gpt-5.1-codex", reasoningEffort: "medium" },
    { id: "gpt-5.1", reasoningEffort: "medium" },
    // Non-reasoning models as fallback
    { id: "claude-sonnet-4" },
    { id: "claude-sonnet-4.5" },
  ],
  reasoning: [
    { id: "gpt-5", reasoningEffort: "high" },
    { id: "gpt-5.4", reasoningEffort: "high" },
    { id: "claude-sonnet-4.6", reasoningEffort: "high" },
    { id: "claude-opus-4.5" },
    { id: "claude-opus-4.6" },
    { id: "claude-opus-4.6-1m" },
    { id: "gpt-5.1-codex-max", reasoningEffort: "high" },
  ],
};

/**
 * Assign each model to a provider family.
 * Derived directly from MODEL_CANDIDATES so it never drifts out of sync.
 * Unknown models are skipped silently — callers handle null returns from
 * getModelFamily().
 *
 * @type {{ claude: Set<string>, gpt: Set<string> }}
 */
export const MODEL_FAMILIES = (() => {
  const claude = new Set();
  const gpt = new Set();
  for (const tier of Object.values(MODEL_CANDIDATES)) {
    for (const { id } of tier) {
      if (id.startsWith("claude-")) claude.add(id);
      else if (id.startsWith("gpt-")) gpt.add(id);
    }
  }
  return { claude, gpt };
})();

/**
 * Multi-token phrases whose presence in a prompt triggers reasoning-tier
 * escalation for implementation/general tasks (per routing-matrix.md).
 *
 * Rationale for omitting bare "orchestrate"/"orchestration": those words
 * appeared in false-positive contexts (e.g. asking about orchestration
 * concepts in docs) without implying a multi-agent workload. Only
 * unambiguous action phrases are included.
 */
export const ORCHESTRATION_KEYWORDS = [
  "parallel agents",
  "multiple agents",
  "multi-agent",
  "parallel tools",
  "tool chain",
  "chained tools",
];

